    io_service_t service = IOServiceGetMatchingService(
        kIOMainPortDefault,
        IOServiceMatching("IOGPU")
    );
    if (service == IO_OBJECT_NULL) {
        NSLog(@"[CVE-2025-24257] IOGPU service not found");
        return;
